#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
#define min(a,b) ((a)<(b)?(a):(b))
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(LL k){if(k>9)print(k/10);putchar(k%10+'0');}
const int N=1e5+10,M=1e6+10;int dfn[N],low[N],n,m,Rt,tot,siz[N];LL Sm,ans[N];
int head[N],des[M],nxt[M],cgt;inline void ins(int x,int y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;}
inline void tarjan(int u)
{
	dfn[u]=low[u]=++tot;int sm=n-(siz[u]=1);
	grep(u,i)
	{
		int v=des[i];if(!dfn[v])
		{
			tarjan(v);low[u]=min(low[u],low[v]);siz[u]+=siz[v];
			if(u!=Rt&&low[v]>=dfn[u])ans[u]+=1ll*siz[v]*(siz[v]-1),sm-=siz[v];
		}
		low[u]=min(low[u],dfn[v]);
	}
	if(u!=Rt)ans[u]+=1ll*sm*(sm-1);return;
}
int main()
{
	n=read();m=read();rep(1,m,i){int x=read(),y=read();ins(x,y);ins(y,x);}
	Sm=1ll*(n-1)*(n-2);tarjan(Rt=1);
	memset(dfn,0,sizeof(dfn));memset(low,0,sizeof(low));memset(siz,0,sizeof(siz));
	rep(1,n-1,i)ans[i]=0;tot=0;tarjan(Rt=n);
	rep(1,n,i)printf("%lld\n",Sm-ans[i]+(n-1)*2);
//	print(Sm-ans[i]),putchar('\n');return 0;
}
